using System.ComponentModel;
using System.Net;
using System.Text;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

var notebook = new Notebook();

IList<AITool> tools =
[
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notebook.TakeNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
];

// ---------------------------------------------------------------------------
// Chat client with automatic function-calling loop
// ---------------------------------------------------------------------------

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// System prompt
// ---------------------------------------------------------------------------

const string systemPrompt = """
    You are a research agent. Your goal is to research a topic thoroughly.

    Workflow:
    1. Search the web with several diverse queries to gather broad information.
    2. Take notes on every important finding — facts, statistics, quotes, sources.
    3. Search for follow-up questions or different perspectives.
    4. Read your notes to review everything you've collected.
    5. Provide a well-structured, comprehensive summary of your research.

    Guidelines:
    - Perform at least 3 different searches to cover multiple angles.
    - Take notes after each search so you don't lose details.
    - Cite the source or context for each finding when possible.
    - End with a clear, organized summary that synthesizes all findings.
    """;

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------

Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
};

var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine();
Console.WriteLine(new string('═', 60));
Console.WriteLine("📋  RESEARCH SUMMARY");
Console.WriteLine(new string('═', 60));
Console.WriteLine(response.Text);
Console.WriteLine(new string('═', 60));

// ===========================================================================
// Tool implementations
// ===========================================================================

// ---- Web Search -----------------------------------------------------------

[Description("Searches the web and returns titles and snippets from the results.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query,
    [Description("Max results to return (1-10)")] int maxResults = 5)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url);
        var results = ParseSearchResults(html, Math.Clamp(maxResults, 1, 10));

        if (results.Count == 0)
            return $"No results found for '{query}'. Try a different query.";

        var sb = new StringBuilder();
        sb.AppendLine($"Results for '{query}':\n");
        for (var i = 0; i < results.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {results[i].Title}");
            if (!string.IsNullOrEmpty(results[i].Snippet))
                sb.AppendLine($"    {results[i].Snippet}");
            sb.AppendLine();
        }

        Console.WriteLine($"  ✅ Found {results.Count} result(s)");
        return sb.ToString();
    }
    catch (Exception ex)
    {
        Console.WriteLine($"  ⚠️  Search failed: {ex.Message}");
        return $"Search failed: {ex.Message}. Try rephrasing your query.";
    }
}

// ---- HTML helpers ---------------------------------------------------------

static List<(string Title, string Snippet)> ParseSearchResults(string html, int max)
{
    var results = new List<(string, string)>();
    var pos = 0;

    while (results.Count < max && pos < html.Length)
    {
        var anchorIdx = html.IndexOf("class=\"result__a\"", pos, StringComparison.Ordinal);
        if (anchorIdx < 0) break;

        var title = ExtractInnerText(html, anchorIdx);

        var snippetIdx = html.IndexOf(
            "class=\"result__snippet\"", anchorIdx, StringComparison.Ordinal);

        var snippet = snippetIdx >= 0 && snippetIdx - anchorIdx < 2000
            ? ExtractInnerText(html, snippetIdx)
            : "";

        if (!string.IsNullOrWhiteSpace(title))
        {
            results.Add((
                WebUtility.HtmlDecode(StripTags(title)).Trim(),
                WebUtility.HtmlDecode(StripTags(snippet)).Trim()));
        }

        pos = snippetIdx >= 0 ? snippetIdx + 1 : anchorIdx + 1;
    }

    return results;
}

static string ExtractInnerText(string html, int attrPos)
{
    var gt = html.IndexOf('>', attrPos);
    if (gt < 0) return "";
    var close = html.IndexOf("</", gt, StringComparison.Ordinal);
    if (close < 0) return "";
    return html[(gt + 1)..close];
}

static string StripTags(string input)
{
    var sb = new StringBuilder(input.Length);
    var inside = false;
    foreach (var ch in input)
    {
        switch (ch)
        {
            case '<': inside = true; break;
            case '>': inside = false; break;
            default:
                if (!inside) sb.Append(ch);
                break;
        }
    }
    return sb.ToString();
}

// ---- Note-taking ----------------------------------------------------------

class Notebook
{
    private readonly List<string> _notes = [];

    [Description(
        "Saves a research note. Use this to record important facts, statistics, " +
        "quotes, or insights discovered during research.")]
    public string TakeNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        var preview = content.Length > 60 ? content[..60] + "…" : content;
        Console.WriteLine($"  📝 Note #{_notes.Count}: {preview}");
        return $"Note #{_notes.Count} saved.";
    }

    [Description(
        "Reads all research notes taken so far. Use this to review collected " +
        "information before writing the final summary.")]
    public string ReadNotes()
    {
        Console.WriteLine($"  📖 Reading notes ({_notes.Count} total)");

        if (_notes.Count == 0)
            return "No notes taken yet. Use TakeNote to save findings.";

        var sb = new StringBuilder();
        sb.AppendLine($"All notes ({_notes.Count} total):\n");
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[Note {i + 1}] {_notes[i]}\n");
        return sb.ToString();
    }
}

